import{_ as i,o,c as t,ae as l}from"./chunks/framework.jfJLTIcL.js";const p=JSON.parse('{"title":"Public Distribution","description":"","frontmatter":{},"headers":[],"relativePath":"en/public-distribution.md","filePath":"en/public-distribution.md","lastUpdated":null}'),a={name:"en/public-distribution.md"};function s(r,e,c,d,n,u){return o(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="public-distribution" tabindex="-1">Public Distribution <a class="header-anchor" href="#public-distribution" aria-label="Permalink to &quot;Public Distribution&quot;">​</a></h1><p>This page explains how the private VILab source repo now publishes into one public distribution repository.</p><h2 id="what-the-public-repo-is-for" tabindex="-1">What the public repo is for <a class="header-anchor" href="#what-the-public-repo-is-for" aria-label="Permalink to &quot;What the public repo is for&quot;">​</a></h2><ul><li>GitHub Releases with installers, checksums, signatures, and <code>latest.json</code></li><li>GitHub Pages with the public website</li><li>Public changelog pages generated from <code>.github/releases/*.md</code></li><li>Stable documentation under <code>/docs/</code></li></ul><p>The source code stays in the private repo. Public users do not need access to the private development history.</p><h2 id="recommended-public-repo-shape" tabindex="-1">Recommended public repo shape <a class="header-anchor" href="#recommended-public-repo-shape" aria-label="Permalink to &quot;Recommended public repo shape&quot;">​</a></h2><ul><li>Repository name: <code>VILab-public</code></li><li>Default branch: <code>main</code></li><li>GitHub Pages source: deploy from the <code>main</code> branch root</li><li>Custom domain: <code>app.&lt;your-domain&gt;</code></li></ul><h2 id="required-private-repo-secrets" tabindex="-1">Required private-repo secrets <a class="header-anchor" href="#required-private-repo-secrets" aria-label="Permalink to &quot;Required private-repo secrets&quot;">​</a></h2><ul><li><code>PUBLIC_RELEASE_REPO</code>: the public repository slug, for example <code>ERRORIGHT-AI/VILab-public</code></li><li><code>PUBLIC_RELEASE_PAT</code>: a token with write access to the public repository</li><li><code>PUBLIC_SITE_DOMAIN</code>: the custom domain, for example <code>app.example.com</code></li></ul><h2 id="what-the-workflows-now-do" tabindex="-1">What the workflows now do <a class="header-anchor" href="#what-the-workflows-now-do" aria-label="Permalink to &quot;What the workflows now do&quot;">​</a></h2><ul><li><code>Sync Public Site</code><ul><li>Builds the docs</li><li>Generates the public homepage, download page, and changelog pages</li><li>Syncs the generated static files to the public repo</li></ul></li><li><code>Windows Release</code><ul><li>Builds the Windows installers</li><li>Generates <code>latest.json</code></li><li>Uploads release assets and notes to the public repo</li></ul></li><li><code>macOS Release</code><ul><li>Builds and verifies the macOS dmg</li><li>Uploads release assets and notes to the public repo</li></ul></li></ul><h2 id="first-time-setup-checklist" tabindex="-1">First-time setup checklist <a class="header-anchor" href="#first-time-setup-checklist" aria-label="Permalink to &quot;First-time setup checklist&quot;">​</a></h2><ol><li>Create the public repository.</li><li>Add an initial commit on <code>main</code>.</li><li>In the public repo settings, enable GitHub Pages from the <code>main</code> branch root.</li><li>Add your custom domain in the Pages settings.</li><li>Point your DNS to GitHub Pages for that custom domain.</li><li>Add the three secrets in the private source repository.</li><li>Trigger <code>Sync Public Site</code> once to seed the public branch contents.</li><li>Trigger a tagged release to verify that release assets land in the public repo.</li></ol><h2 id="local-commands" tabindex="-1">Local commands <a class="header-anchor" href="#local-commands" aria-label="Permalink to &quot;Local commands&quot;">​</a></h2><ul><li>Build the public site artifact: <code>npm run public:site:build</code></li><li>Sync the built site into the public repo: <code>npm run public:repo:sync</code></li><li>Publish a Windows release: <code>npm run release:windows</code></li><li>Publish a macOS release: <code>npm run release:mac</code></li></ul><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li>The desktop app should be built with <code>VITE_PUBLIC_SITE_URL</code> set to your public site origin so the in-app docs link opens the public <code>/docs/</code> path.</li><li>The Tauri updater endpoint now targets the public release repository.</li><li>The existing <code>.github/releases/*.md</code> files remain the single source of truth for release notes.</li></ul>',17)])])}const b=i(a,[["render",s]]);export{p as __pageData,b as default};
